### Change 4 — Add JS functions before `</script>` at the end of the file

Find `function _spBar` and the end of the JS block (near `}</script>`). After the last `}` before `</script>`, add these functions:

```javascript
/* ── References: artists add / remove ── */
function arAdd() {
  const inp = document.getElementById('ar-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.arMax || '50');
  let cnt = parseInt(inp.value);
  if (cnt >= max) return;
  cnt++;
  inp.value = cnt;
  const row = document.querySelector('#ar-list [data-ar-idx="' + cnt + '"]');
  if (row) row.style.display = '';
  _arBar(cnt, max);
  State.dirty['artists.count'] = String(cnt);
  const box = $b('artists-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
function arRemove() {
  const inp = document.getElementById('ar-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.arMax || '50');
  let cnt = parseInt(inp.value);
  if (cnt <= 1) return;
  const row = document.querySelector('#ar-list [data-ar-idx="' + cnt + '"]');
  if (row) row.style.display = 'none';
  cnt--;
  inp.value = cnt;
  _arBar(cnt, max);
  State.dirty['artists.count'] = String(cnt);
  const box = $b('artists-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
function _arBar(cnt, max) {
  const lbl = document.getElementById('ar-bar-lbl');
  if (lbl) lbl.textContent = cnt + ' Künstler';
  const btnR = document.getElementById('ar-remove');
  const btnA = document.getElementById('ar-add');
  if (btnR) btnR.disabled = (cnt <= 1);
  if (btnA) btnA.disabled = (cnt >= max);
}

/* ── References: companies add / remove ── */
function coAdd() {
  const inp = document.getElementById('co-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.coMax || '20');
  let cnt = parseInt(inp.value);
  if (cnt >= max) return;
  cnt++;
  inp.value = cnt;
  const row = document.querySelector('#co-list [data-co-idx="' + cnt + '"]');
  if (row) row.style.display = '';
  _coBar(cnt, max);
  State.dirty['companies.count'] = String(cnt);
  const box = $b('companies-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
function coRemove() {
  const inp = document.getElementById('co-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.coMax || '20');
  let cnt = parseInt(inp.value);
  if (cnt <= 1) return;
  const row = document.querySelector('#co-list [data-co-idx="' + cnt + '"]');
  if (row) row.style.display = 'none';
  cnt--;
  inp.value = cnt;
  _coBar(cnt, max);
  State.dirty['companies.count'] = String(cnt);
  const box = $b('companies-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
function _coBar(cnt, max) {
  const lbl = document.getElementById('co-bar-lbl');
  if (lbl) lbl.textContent = cnt + ' Unternehmen';
  const btnR = document.getElementById('co-remove');
  const btnA = document.getElementById('co-add');
  if (btnR) btnR.disabled = (cnt <= 1);
  if (btnA) btnA.disabled = (cnt >= max);
}
```

