552	/**
553	 * Render a field: static view + in-place input/textarea at same position.
554	 * @param string $key     field key
555	 * @param string $tag     HTML tag for view mode (h1, h2, p, span, div, etc.)
556	 * @param string $class   CSS class(es) for the view tag
557	 * @param bool   $ta      true = textarea, false = input
558	 * @param string $val     current value (HTML-escaped)
559	 * @param array  $attrs   extra HTML attributes for view tag
560	 * @param int    $rows    textarea rows
561	 */
562	function field(string $key, string $tag, string $class, bool $ta, string $val, array $attrs = [], int $rows = 2): string {
563	    global $limits;
564	    $max     = $limits[$key] ?? 200;
565	    $rawVal  = htmlspecialchars_decode($val);
566	    $attrStr = '';
567	    foreach ($attrs as $ak => $av) {
568	        $attrStr .= ' '.$ak.'="'.htmlspecialchars($av).'"';
569	    }
570	    $safeVal = htmlspecialchars($rawVal, ENT_QUOTES);
571	    $len     = mb_strlen($rawVal);
572	    $cntCls  = $len > $max ? 'e' : ($len > $max * .85 ? 'w' : '');
573	
574	    $viewCls  = $class ? ' class="'.$class.'"' : '';
575	    $viewTag  = "<{$tag}{$viewCls}{$attrStr} data-field-view=\"{$key}\">{$val}</{$tag}>";
576	
577	    $inputCls = 'cms-'.($ta?'ta':'inp');
578	    $input = $ta
579	        ? "<textarea class=\"{$inputCls}\" data-field-input=\"{$key}\" data-max=\"{$max}\" rows=\"{$rows}\" autocomplete=\"off\">{$safeVal}</textarea>"
580	        : "<input type=\"text\" class=\"{$inputCls}\" data-field-input=\"{$key}\" data-max=\"{$max}\" value=\"{$safeVal}\" autocomplete=\"off\">";
581	    $cnt = "<span class=\"cms-cnt {$cntCls}\" data-cnt=\"{$key}\">{$len}/{$max}</span>";
582	
583	    return "<div class=\"view-mode\" data-field-vm=\"{$key}\">{$viewTag}</div>
584	<div class=\"edit-mode\" data-field-em=\"{$key}\">{$input}{$cnt}</div>";
585	}
