/* ── References: artists add / remove ── */
function arAdd() {
  const inp = document.getElementById('ar-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.arMax || '50');
  let cnt = parseInt(inp.value);
  if (cnt >= max) return;
  cnt++;
  inp.value = cnt;
  const row = document.querySelector('#ar-list [data-ar-idx="' + cnt + '"]');
  if (row) row.style.display = '';
  _arBar(cnt, max);
  State.dirty['artists.count'] = String(cnt);
  const box = $b('artists-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
function arRemove() {
  const inp = document.getElementById('ar-count-inp');
  if (!inp) return;
  const max = parseInt(inp.dataset.arMax || '50');
  let cnt = parseInt(inp.value);
  if (cnt <= 1) return;
  const row = document.querySelector('#ar-list [data-ar-idx="' + cnt + '"]');
  if (row) row.style.display = 'none';
  cnt--;
  inp.value = cnt;
  _arBar(cnt, max);
  State.dirty['artists.count'] = String(cnt);
  const box = $b('artists-section');
  if (box) box.classList.add('is-dirty');
  updateSaveBar();
}
